import Autocomplete from '@mui/material/Autocomplete';
import Box from '@mui/material/Box';
import Button from '@mui/material/Button';
import Card from '@mui/material/Card';
import CardContent from '@mui/material/CardContent';
import TextField from '@mui/material/TextField';
import Typography from '@mui/material/Typography';
import { Container, display } from '@mui/system';
import Cookies from 'js-cookie';
import { useEffect, useState } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import { setUser } from '../store/auth.js';
import { AdapterDayjs } from '@mui/x-date-pickers/AdapterDayjs';
import { DesktopDatePicker } from '@mui/x-date-pickers/DesktopDatePicker';
import { LocalizationProvider } from '@mui/x-date-pickers/LocalizationProvider';
import DeleteSharpIcon from '@mui/icons-material/DeleteSharp';
import EditSharpIcon from '@mui/icons-material/EditSharp';
import IconButton from '@mui/material/IconButton';
import Paper from '@mui/material/Paper';
import Table from '@mui/material/Table';
import TableBody from '@mui/material/TableBody';
import TableCell from '@mui/material/TableCell';
import TableContainer from '@mui/material/TableContainer';
import TableHead from '@mui/material/TableHead';
import TableRow from '@mui/material/TableRow';
import dayjs from 'dayjs';
const InitialForm = {
  label: '',
  icon: '',
};
let d = {
  data: [
    {
      _id: 11,
      transactions: [
        {
          amount: 100,
          description: 'Shoes',
          date: '2022-11-15T11:35:40.951Z',
          category: 'Travel',
          _id: '637379908d9ba3763533dc8e',
        },
        {
          amount: 200,
          description: 'hat',
          date: '2022-11-15T11:50:08.739Z',
          category: 'shopping',
          _id: '63737da6ad4049b575061382',
        },
        {
          amount: 0,
          description: 'gun',
          date: '2022-11-15T13:15:01.232Z',
          category: 'shopping',
          _id: '637392f2e8b6d92eead91845',
        },
        {
          amount: 100,
          description: 'books',
          date: '2022-11-15T13:15:01.232Z',
          category: 'travel',
          _id: '637394ab75c35139fbe25563',
        },
        {
          amount: 100,
          description: 'ice',
          date: '2022-11-16T16:22:50.118Z',
          category: 'shopping',
          _id: '63750f7c3deab59b3fadb2e4',
        },
      ],
      totalExpenses: 500,
    },
  ],
};
d.data.forEach((s) => {
  s.transactions.forEach((row) => {
    console.log(row.description);
  });
});

const icons = ['User'];

export default function CategoryForm() {
  // { editCategory }
  const user = useSelector((state) => state.auth.user);
  const dispatch = useDispatch();
  const token = Cookies.get('token');
  const [form, setForm] = useState(InitialForm);
  // const [details, setDetails] = useState(InitialDetails);
  //const [filters, setFilter] = useState([]);

  // useEffect(() => {
  //   if (editCategory._id !== undefined) {
  //     setForm(editCategory);
  //   }
  // }, [editCategory]);

  async function fetchFilterList() {
    const token = Cookies.get('token');
    console.log('Hello', JSON.stringify(form));
    const res = await fetch(
      `${process.env.REACT_APP_API_URL}/filter?priceCategory=${
        form.priceRadio
      }&category=${form.category.label || undefined}&sDate=${
        form.sDate
      }&eDate=${form.eDate}`,
      {
        headers: {
          Authorization: `Bearer ${token}`,
        },
      }
    );
    d = await res.json();
    console.log(`Response i ${JSON.stringify(d)}`);
    //setFilter(data);
  }

  function handleChange(e) {
    setForm({ ...form, [e.target.name]: e.target.value });
  }

  function handleStartDate(newValue) {
    setForm({ ...form, sDate: newValue });
  }

  function handleEndDate(newValue) {
    setForm({ ...form, eDate: newValue });
  }

  function handleCategory(newValue) {
    setForm({ ...form, category: newValue });
  }

  async function handleSubmit(e) {
    e.preventDefault();
    console.log('qewqe');
    fetchFilterList();
  }

  function reload(res, _user) {
    if (res.ok) {
      dispatch(setUser({ user: _user }));
      //   setDetails(InitialDetails);
    }
  }

  // async function create() {
  //   const res = await fetch(`${process.env.REACT_APP_API_URL}/category`, {
  //     method: 'POST',
  //     body: JSON.stringify(form),
  //     headers: {
  //       'content-type': 'application/json',
  //       Authorization: `Bearer ${token}`,
  //     },
  //   });

  //   const _user = {
  //     ...user,
  //     categories: [...user.categories, { ...form }],
  //   };
  //   reload(res, _user);
  // }

  // async function update() {
  //   const res = await fetch(
  //     `${process.env.REACT_APP_API_URL}/category/${editCategory._id}`,
  //     {
  //       method: 'PATCH',
  //       body: JSON.stringify(form),
  //       headers: {
  //         'content-type': 'application/json',
  //         Authorization: `Bearer ${token}`,
  //       },
  //     }
  //   );
  //   const _user = {
